solutions.javascript:
// Solution
function serveStaticFiles(app, directory) {
	if (directory !== '/') {
		return false;
	}
	var file = require('fs').readFileSync(directory + 'index.js', 'utf8');
	app.get('*', (req, res) => {
		if (req.path === '/') {
			res.send(file);
		} else {
			res.status(404).send('Not Found');
		}
	});
	return true;
}

solutions.python:
class Solution:
	def serveStaticFiles(self, app, directory):
		if directory != '/':
			return False
		file = open(directory + 'index.js', 'r').read()
		app.get('*', self.handle_request)
		return True

	def handle_request(self, req, res):
		if req.path == '/':
			res.send(file)
		else:
			res.status(404).send('Not Found')
